import React, { memo } from "react";
import { NavLink } from "react-router-dom";

const LINKS = [
  { to: "/dashboard", label: "Dashboard",      icon: "📊" },
  { to: "/obras",     label: "Listado Obras",  icon: "🏗️" },
  { to: "/historico", label: "Histórico",      icon: "📅" },
];

function Sidebar() {
  return (
    <aside className="hidden lg:flex flex-col w-56 bg-white border-r border-gray-200 min-h-screen py-6 px-3">
      <nav className="space-y-1 flex-1">
        {LINKS.map(({ to, label, icon }) => (
          <NavLink
            key={to}
            to={to}
            className={({ isActive }) =>
              `flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors duration-150
               ${isActive
                 ? "bg-primary-50 text-primary-700 border border-primary-100"
                 : "text-gray-600 hover:bg-gray-50 hover:text-gray-900"}`
            }
          >
            <span className="text-base">{icon}</span>
            {label}
          </NavLink>
        ))}
      </nav>

      <div className="mt-auto px-3 py-3 bg-gray-50 rounded-lg">
        <p className="text-xs text-gray-400 font-medium uppercase tracking-wide">Sistema</p>
        <p className="text-xs text-gray-500 mt-0.5">v1.0.0 · Mock Mode</p>
      </div>
    </aside>
  );
}

export default memo(Sidebar);
